--- 文件: D:\LLM\memory\agentmemory\src\functions\search.ts (第 220 至 546 行，共 546 行) ---
 220 | export async function rebuildIndex(kv: StateKV): Promise<number> {
 221 |   const idx = getSearchIndex()
 222 |   idx.clear()
 223 | 
 224 |   // BM25 clear above wipes stale doc entries; the vector index has the
 225 |   // symmetric concern — memories/observations deleted between runs
 226 |   // would leave orphan embeddings here forever. Clear both before the
 227 |   // repopulation loops run, so BM25 and vector stay in sync.
 228 |   vectorIndex?.clear()
 229 | 
 230 |   const batchSize = getRebuildEmbedBatchSize()
 231 |   // Accumulator for the batched embed flush. BM25 add is synchronous and
 232 |   // doesn't need batching — only the vector path benefits.
 233 |   type EmbedJob = {
 234 |     id: string
 235 |     sessionId: string
 236 |     text: string
 237 |     context: { kind: "memory" | "observation" | "synthetic"; logId: string }
 238 |   }
 239 |   const pending: EmbedJob[] = []
 240 |   let count = 0
 241 | 
 242 |   const flush = async (): Promise<void> => {
 243 |     if (pending.length === 0) return
 244 |     await vectorIndexAddBatchGuarded(pending)
 245 |     pending.length = 0
 246 |   }
 247 |   const enqueue = async (job: EmbedJob): Promise<void> => {
 248 |     pending.push(job)
 249 |     if (pending.length >= batchSize) await flush()
 250 |   }
 251 | 
 252 |   // Memories live in their own KV scope outside per-session observation
 253 |   // scopes, so they need a separate walk. Without this, mem::remember
 254 |   // entries vanish from BM25 on every restart even after the live-write
 255 |   // fix in remember.ts (#257).
 256 |   try {
 257 |     const memories = await kv.list<Memory>(KV.memories)
 258 |     for (const memory of memories) {
 259 |       if (memory.isLatest === false) continue
 260 |       if (!memory.title || !memory.content) continue
 261 |       idx.add(memoryToObservation(memory))
 262 |       await enqueue({
 263 |         id: memory.id,
 264 |         sessionId: memory.sessionIds?.[0] ?? 'memory',
 265 |         text: memory.title + ' ' + memory.content,
 266 |         context: { kind: "memory", logId: memory.id },
 267 |       })
 268 |       count++
 269 |     }
 270 |   } catch (err) {
 271 |     logger.warn('rebuildIndex: failed to load memories', {
 272 |       error: err instanceof Error ? err.message : String(err),
 273 |     })
 274 |   }
 275 | 
 276 |   const sessions = await kv.list<Session>(KV.sessions)
 277 |   if (!sessions.length) {
 278 |     await flush()
 279 |     return count
 280 |   }
 281 | 
 282 |   const obsPerSession: CompressedObservation[][] = []
 283 |   const failedSessions: string[] = []
 284 |   for (let batch = 0; batch < sessions.length; batch += 10) {
 285 |     const chunk = sessions.slice(batch, batch + 10)
 286 |     const results = await Promise.all(
 287 |       chunk.map(async (s) => {
 288 |         try {
 289 |           return await kv.list<CompressedObservation>(KV.observations(s.id))
 290 |         } catch {
 291 |           failedSessions.push(s.id)
 292 |           return [] as CompressedObservation[]
 293 |         }
 294 |       })
 295 |     )
 296 |     obsPerSession.push(...results)
 297 |   }
 298 |   if (failedSessions.length > 0) {
 299 |     logger.warn('rebuildIndex: failed to load observations for sessions', { failedSessions })
 300 |   }
 301 |   for (const observations of obsPerSession) {
 302 |     for (const obs of observations) {
 303 |       if (obs.title && obs.narrative) {
 304 |         idx.add(obs)
 305 |         await enqueue({
 306 |           id: obs.id,
 307 |           sessionId: obs.sessionId,
 308 |           text: obs.title + ' ' + obs.narrative,
 309 |           context: { kind: "observation", logId: obs.id },
 310 |         })
 311 |         count++
 312 |       }
 313 |     }
 314 |   }
 315 | 
 316 |   // Drain the last partial batch.
 317 |   await flush()
 318 |   return count
 319 | }
 320 | 
